const city = $fromAI('city', 'the city to search for co-living properties');

try {
  const mockProperties = generateMockCoLivingProperties(city);
  return {
    success: true,
    city,
    propertiesFound: mockProperties.length,
    properties: mockProperties,
    searchSources: ['PadSplit', 'Co-living.com', 'SpareRoom'],
    searchDate: new Date().toISOString()
  };
} catch (error) {
  return { success: false, error: error.message };
}

function generateMockCoLivingProperties(city) {
  const properties = [];
  const propertyCount = Math.floor(Math.random() * 15) + 10;
  const propertyTypes = ['Converted House', 'Purpose-Built Co-Living', 'Apartment Building'];
  const neighborhoods = ['Downtown', 'University District', 'Tech Corridor', 'Arts District'];

  for (let i = 0; i < propertyCount; i++) {
    const roomCount = Math.floor(Math.random() * 8) + 4;
    const baseRent = Math.floor(Math.random() * 500) + 600;

    properties.push({
      id: `prop_${city.toLowerCase().replace(/[^a-z0-9]/g, '_')}_${i + 1}`,
      name: `${neighborhoods[Math.floor(Math.random() * neighborhoods.length)]} Co-Living`,
      type: propertyTypes[Math.floor(Math.random() * propertyTypes.length)],
      neighborhood: neighborhoods[Math.floor(Math.random() * neighborhoods.length)],
      totalRooms: roomCount,
      availableRooms: Math.floor(Math.random() * 3),
      priceRange: {
        min: baseRent,
        max: baseRent + Math.floor(Math.random() * 300)
      }
    });
  }
  return properties;
}

const propertyIds = $fromAI('property_ids', 'comma-separated list of co-living property IDs');
const city = $fromAI('city', 'the city being analyzed');

try {
  const ids = propertyIds.split(',').map(id => id.trim()).slice(0, 12);
  const results = [];

  for (const propertyId of ids) {
    const analysis = analyzeProperty(propertyId);
    results.push(analysis);
  }

  const marketSummary = calculateMarketSummary(results, city);

  return {
    success: true,
    city,
    marketSummary,
    propertyResults: results.slice(0, 8),
    analysisDate: new Date().toISOString()
  };
} catch (error) {
  return { success: false, error: error.message };
}

function analyzeProperty(propertyId) {
  const roomCount = Math.floor(Math.random() * 6) + 5;
  let roomsMeeting75_55 = 0;
  let totalRevenue = 0;

  for (let i = 0; i < roomCount; i++) {
    const occupancy30 = 60 + Math.random() * 40;
    const occupancy60 = 50 + Math.random() * 35;
    const rent = 700 + Math.floor(Math.random() * 400);

    if (occupancy30 >= 75 && occupancy60 >= 55) {
      roomsMeeting75_55++;
    }

    totalRevenue += rent * (occupancy30 / 100);
  }

  const propertyOccupancy30 = 65 + Math.random() * 30;
  const propertyOccupancy60 = 60 + Math.random() * 25;

  return {
    propertyId,
    totalRooms: roomCount,
    propertyOccupancy30Day: Math.round(propertyOccupancy30 * 10) / 10,
    propertyOccupancy60Day: Math.round(propertyOccupancy60 * 10) / 10,
    propertyMeets75_55Rule: propertyOccupancy30 >= 75 && propertyOccupancy60 >= 55,
    roomsMeeting75_55Rule: roomsMeeting75_55,
    roomOccupancyRate: Math.round((roomsMeeting75_55 / roomCount) * 100),
    projectedMonthlyRevenue: Math.round(totalRevenue)
  };
}

function calculateMarketSummary(results, city) {
  const totalProperties = results.length;
  const propertiesMeeting75_55 = results.filter(r => r.propertyMeets75_55Rule).length;
  const totalRooms = results.reduce((sum, r) => sum + r.totalRooms, 0);
  const roomsMeeting75_55 = results.reduce((sum, r) => sum + r.roomsMeeting75_55Rule, 0);
  const totalRevenue = results.reduce((sum, r) => sum + r.projectedMonthlyRevenue, 0);

  return {
    city,
    totalPropertiesAnalyzed: totalProperties,
    propertiesMeeting75_55Rule: propertiesMeeting75_55,
    marketScore: Math.round((propertiesMeeting75_55 / totalProperties) * 100),
    totalRoomsAnalyzed: totalRooms,
    roomsMeeting75_55Rule: roomsMeeting75_55,
    roomLevelMarketScore: Math.round((roomsMeeting75_55 / totalRooms) * 100),
    totalProjectedMonthlyRevenue: Math.round(totalRevenue),
    avgRevenuePerProperty: Math.round(totalRevenue / totalProperties),
    marketRecommendation: generateRecommendation(propertiesMeeting75_55, totalProperties)
  };
}

function generateRecommendation(qualifying, total) {
  const score = (qualifying / total) * 100;
  if (score >= 60) return 'Excellent Co-Living Market';
  if (score >= 45) return 'Strong Co-Living Potential';
  if (score >= 30) return 'Moderate Co-Living Market';
  return 'Challenging Co-Living Market';
}

const analysisData = JSON.parse($fromAI('analysis_data', 'JSON string containing co-living analysis results'));
const city = $fromAI('city', 'the city being analyzed');

try {
  const { marketSummary, propertyResults } = analysisData;

  const report = {
    title: `Co-Living Market Analysis: ${city}`,
    executiveSummary: {
      marketScore: marketSummary.marketScore,
      roomLevelScore: marketSummary.roomLevelMarketScore,
      recommendation: marketSummary.marketRecommendation,
      totalRevenuePotential: `$${marketSummary.totalProjectedMonthlyRevenue.toLocaleString()}/month`,
      investmentReadiness: marketSummary.marketScore >= 50 ? 'Ready for Investment' : 'Proceed with Caution'
    },
    marketMetrics: {
      propertiesAnalyzed: marketSummary.totalPropertiesAnalyzed,
      roomsAnalyzed: marketSummary.totalRoomsAnalyzed,
      propertiesMeetingRule: `${marketSummary.propertiesMeeting75_55Rule} (${marketSummary.marketScore}%)`,
      roomsMeetingRule: `${marketSummary.roomsMeeting75_55Rule} (${marketSummary.roomLevelMarketScore}%)`,
      avgRevenuePerProperty: `$${marketSummary.avgRevenuePerProperty}/month`
    },
    topPerformers: propertyResults
      .filter(p => p.propertyMeets75_55Rule)
      .sort((a, b) => b.projectedMonthlyRevenue - a.projectedMonthlyRevenue)
      .slice(0, 3)
      .map(property => ({
        propertyId: property.propertyId,
        totalRooms: property.totalRooms,
        monthlyRevenue: `$${property.projectedMonthlyRevenue}`,
        status: 'Meets Co-Living 75/55 Rule ✅'
      })),
    investmentRecommendations: generateRecommendations(marketSummary),
    coLivingConsiderations: [
      'Multi-room properties offer income diversification but require higher management',
      'Co-living tenants typically stay 3-12 months with flexible lease terms',
      'Common areas (kitchen, living room, laundry) are essential for success',
      'Target demographics: young professionals, students, remote workers',
      'Consider local regulations for shared housing and room rental permits'
    ],
    nextSteps: [
      'Research zoning laws and shared housing regulations',
      'Analyze property acquisition costs vs. projected rental income',
      'Evaluate property management options for co-living operations',
      'Study successful operators in the market (PadSplit, Common, etc.)',
      'Consider renovation costs for converting properties'
    ],
    reportMetadata: {
      generatedAt: new Date().toISOString(),
      analysisMethod: 'Co-Living Adapted 75/55 Rule',
      marketConfidence: marketSummary.totalPropertiesAnalyzed >= 10 ? 'High' : 'Medium'
    }
  };

  const formattedReport = formatReport(report);

  return { success: true, report, formattedReport };
} catch (error) {
  return { success: false, error: error.message };
}

function generateRecommendations(marketSummary) {
  const recommendations = [];
  const { marketScore, avgRevenuePerProperty } = marketSummary;

  if (marketScore >= 60) {
    recommendations.push('✅ Excellent market - actively pursue acquisitions');
    recommendations.push('🏠 Focus on 6-8 room properties for optimal balance');
  } else if (marketScore >= 40) {
    recommendations.push('⚠️ Good potential - be selective about location');
    recommendations.push('🎯 Target properties near universities or employment centers');
  } else {
    recommendations.push('❌ Challenging market - consider alternatives');
    recommendations.push('🔍 Focus on micro-markets with specific drivers');
  }

  if (avgRevenuePerProperty >= 4000) {
    recommendations.push('💰 High revenue potential - premium market');
  } else {
    recommendations.push('💵 Moderate revenue - focus on efficiency');
  }

  return recommendations;
}

function formatReport(report) {
  return `# 🏠 ${report.title}\n\n## 📊 Executive Summary\n- **Market Score:** ${report.executiveSummary.marketScore}%\n- **Room-Level Score:** ${report.executiveSummary.roomLevelScore}%\n- **Recommendation:** ${report.executiveSummary.recommendation}\n- **Monthly Revenue Potential:** ${report.executiveSummary.totalRevenuePotential}\n- **Investment Status:** ${report.executiveSummary.investmentReadiness}\n\n## 📈 Market Metrics\n- **Properties Analyzed:** ${report.marketMetrics.propertiesAnalyzed}\n- **Rooms Analyzed:** ${report.marketMetrics.roomsAnalyzed}\n- **Properties Meeting Rule:** ${report.marketMetrics.propertiesMeetingRule}\n- **Rooms Meeting Rule:** ${report.marketMetrics.roomsMeetingRule}\n- **Avg Revenue/Property:** ${report.marketMetrics.avgRevenuePerProperty}\n\n## 🏆 Top Performers\n${report.topPerformers.map(p => `- **${p.propertyId}**: ${p.totalRooms} rooms, ${p.monthlyRevenue}/month ${p.status}`).join('\n')}\n\n## 💡 Recommendations\n${report.investmentRecommendations.join('\n')}\n\n## 🏠 Co-Living Considerations\n${report.coLivingConsiderations.map((item, i) => `${i + 1}. ${item}`).join('\n')}\n\n## 🎯 Next Steps\n${report.nextSteps.map((step, i) => `${i + 1}. ${step}`).join('\n')}\n\n---\n*Analysis completed at ${new Date(report.reportMetadata.generatedAt).toLocaleString()}*`;
}
